#!/usr/bin/env python3
# =============================================================================
# SCRIPT METADATA (Generated by g_code)
# =============================================================================
"""
Step ID: step02
Step Name: extract_theta_scores
RQ: results/ch7/7.7.3
Generated: 2026-01-09

PURPOSE:
Load omnibus theta_all scores from Ch5 5.1.1 outputs and aggregate by participant.
Ch5 data is test-level (4 rows per participant), needs participant-level means for
regression analysis against RAVLT scores.

EXPECTED INPUTS:
  - results/ch5/5.1.1/data/step03_theta_scores.csv
    Columns: ['UID', 'test', 'Theta_All']
    Test-level theta scores (N=400 rows: 100 participants × 4 tests)

EXPECTED OUTPUTS:
  - results/ch7/7.7.3/data/step02_theta_scores.csv
    Columns: ['UID', 'theta_all', 'theta_standardized']
    Participant-level theta means (N=100 rows)

VALIDATION CRITERIA:
  - Theta scores: approximately -4 to 4 range (IRT ability scale)
  - N=100 participants after aggregation
  - No missing values

g_code REASONING:
- Approach: Load Ch5 test-level data, aggregate by UID (mean), standardize
- Why this approach: Regression needs participant-level predictors (1 row per person)
- Data flow: Ch5 step03 -> groupby(UID).mean() -> standardize -> save
- Expected performance: <5 seconds

IMPLEMENTATION NOTES:
- Analysis tool: Custom aggregation (avoid tools function signature mismatch)
- Column name: 'Theta_All' (uppercase T and A - from actual Ch5 file)
- Aggregation: Mean across 4 tests per participant (omnibus ability estimate)
"""
# =============================================================================

import sys
from pathlib import Path
import pandas as pd
import numpy as np

# Add project root to path for imports
PROJECT_ROOT = Path(__file__).resolve().parents[4]
sys.path.insert(0, str(PROJECT_ROOT))

# RQ directory
RQ_DIR = Path(__file__).resolve().parents[1]
LOG_FILE = RQ_DIR / "logs" / "step02_extract_theta_scores.log"
OUTPUT_FILE = RQ_DIR / "data" / "step02_theta_scores.csv"

# =============================================================================
# Logging Function
# =============================================================================

def log(msg):
    """Write to both log file and console."""
    with open(LOG_FILE, 'a', encoding='utf-8') as f:
        f.write(f"{msg}\n")
        f.flush()
    print(msg, flush=True)

# =============================================================================
# Main Analysis
# =============================================================================

if __name__ == "__main__":
    try:
        log("[START] Step 02: Extract Theta Scores")

        # =========================================================================
        # STEP 1: Load Ch5 Theta Scores
        # =========================================================================
        log("[LOAD] Loading Ch5 5.1.1 theta scores...")

        theta_path = PROJECT_ROOT / "results" / "ch5" / "5.1.1" / "data" / "step03_theta_scores.csv"
        theta_df = pd.read_csv(theta_path)

        log(f"[LOADED] {theta_path.name} ({len(theta_df)} rows, {len(theta_df.columns)} columns)")
        log(f"[INFO] Columns: {theta_df.columns.tolist()}")

        # =========================================================================
        # STEP 2: Aggregate by Participant
        # =========================================================================
        # Ch5 data is test-level (4 rows per participant: test 1-4)
        # Need participant-level means for regression analysis
        log("[AGGREGATE] Computing participant-level theta means...")

        # Verify column name (actual file has 'Theta_All' not 'theta_all')
        if 'Theta_All' not in theta_df.columns:
            log(f"[ERROR] Expected column 'Theta_All' not found")
            log(f"[INFO] Available columns: {theta_df.columns.tolist()}")
            sys.exit(1)

        # Group by UID and compute mean theta across 4 tests
        participant_theta = theta_df.groupby('UID')['Theta_All'].mean().reset_index()
        participant_theta.columns = ['UID', 'theta_all']

        log(f"[AGGREGATED] {len(participant_theta)} participants")

        # =========================================================================
        # STEP 3: Standardize Theta Scores
        # =========================================================================
        log("[STANDARDIZE] Computing z-scores...")

        participant_theta['theta_standardized'] = (
            (participant_theta['theta_all'] - participant_theta['theta_all'].mean()) /
            participant_theta['theta_all'].std()
        )

        log("[STANDARDIZED] Theta scores converted to z-scores")

        # =========================================================================
        # STEP 4: Validation Checks
        # =========================================================================
        log("[VALIDATION] Running validation checks...")

        # Check theta range (IRT ability scale typically -4 to 4)
        min_theta = participant_theta['theta_all'].min()
        max_theta = participant_theta['theta_all'].max()
        mean_theta = participant_theta['theta_all'].mean()
        sd_theta = participant_theta['theta_all'].std()

        log(f"[INFO] Theta range: [{min_theta:.2f}, {max_theta:.2f}]")
        log(f"[INFO] Theta M={mean_theta:.2f}, SD={sd_theta:.2f}")

        if min_theta < -4 or max_theta > 4:
            log(f"[WARNING] Theta scores outside typical IRT range (-4 to 4)")
        else:
            log("[PASS] Theta scores within expected IRT range")

        # Check for missing data
        n_missing = participant_theta.isnull().sum().sum()
        if n_missing > 0:
            log(f"[WARNING] {n_missing} missing values detected")
        else:
            log("[PASS] No missing values")

        # Check participant count
        expected_n = 100
        actual_n = len(participant_theta)
        if actual_n != expected_n:
            log(f"[WARNING] Expected {expected_n} participants, found {actual_n}")
        else:
            log(f"[PASS] N={actual_n} participants (as expected)")

        # =========================================================================
        # STEP 5: Save Output
        # =========================================================================
        log("[SAVE] Saving participant-level theta scores...")

        participant_theta.to_csv(OUTPUT_FILE, index=False, encoding='utf-8')

        log(f"[SAVED] {OUTPUT_FILE} ({len(participant_theta)} participants, {len(participant_theta.columns)} columns)")

        # =========================================================================
        # Summary Statistics
        # =========================================================================
        log("[SUMMARY] Descriptive statistics:")
        log(f"  Theta_all: M={participant_theta['theta_all'].mean():.2f}, SD={participant_theta['theta_all'].std():.2f}")
        log(f"  Theta_all: Range=[{participant_theta['theta_all'].min():.2f}, {participant_theta['theta_all'].max():.2f}]")
        log(f"  Theta_standardized: M={participant_theta['theta_standardized'].mean():.2f}, SD={participant_theta['theta_standardized'].std():.2f}")

        log("[SUCCESS] Step 02 complete")
        sys.exit(0)

    except Exception as e:
        log(f"[ERROR] {str(e)}")
        log("[TRACEBACK] Full error details:")
        import traceback
        with open(LOG_FILE, 'a', encoding='utf-8') as f:
            traceback.print_exc(file=f)
        traceback.print_exc()
        sys.exit(1)
